#include <bits/stdc++.h>
using namespace std;
bool a[100000010];
long long b[100000010],k;
int main() {
	long long n,m;
	cin>>n;
	for(long long i=0;i<n;i++){
		cin>>m;
		for (int i = 2; i <= n; i++) {
				if (!a[i]) {
					b[k++] = i;
				}
				for (int j = 0; j<k && i * b[j] < n; j++) {
					a[b[j]*i] = 1;
					if (i % b[j] == 0) {
						break;
					}
				}
			}
	for(long long j=1;m!=1;j++){
		if(m%b[j]==0){
			m/=b[j];
			cout<<b[j]<<" ";
			b[j]--;
		}
	}cout<<endl;}
	return 0;
}
